import subprocessfrom criresviz.common import SKYfrom criresviz.skycalc.defaults import (    DEFAULT_SKYCALC_PARAMETERS,)import logginglogger = logging.getLogger(__name__)"""Utilities for generating atmospheric transmission and radiance modelsusing ESO SkyCalc."""# Help Functionsdef write_input(filename, parameters):    """    Write a SkyCalc input parameter file.        Parameters    ----------    filename : str or pathlib.Path        Output input-file path.    parameters : dict        SkyCalc input parameters.    """    with open(filename, "w") as f:        for key, value in parameters.items():            f.write(f"{key:<16}: {value}\n")                                      def run_skycalc(input_file, output_file):    """    Execute SkyCalc from the command line.    Parameters    ----------    input_file : str or pathlib.Path        SkyCalc input file.    output_file : str or pathlib.Path        Output FITS file.    """    subprocess.run(        [            "skycalc_cli",            "-i",            str(input_file),            "-o",            str(output_file),        ],        check=True,        capture_output=True,        text=True,    )                        def compute_sky(**kwargs):    """    Generate an atmospheric model using ESO SkyCalc.    Parameters    ----------    **kwargs        SkyCalc parameters that override the default configuration.    Returns    -------    pathlib.Path        Path to the generated FITS file.    Raises    ------    KeyError        If an unknown SkyCalc parameter is supplied.    subprocess.CalledProcessError        If the SkyCalc execution fails.    """    parameters = DEFAULT_SKYCALC_PARAMETERS.copy()    for key, value in kwargs.items():        if key not in DEFAULT_SKYCALC_PARAMETERS:            raise KeyError(                f"Unknown SkyCalc parameter: '{key}'"            )        parameters[key] = value    SKY.mkdir(        parents=True,        exist_ok=True,    )    input_file = SKY / "default.input"    output_file = SKY / "default.fits"    write_input(        input_file,        parameters,    )    logger.info("Running SkyCalc...")    try:        run_skycalc(            input_file,            output_file,        )    except subprocess.CalledProcessError as e:        raise RuntimeError(            "SkyCalc failed.\n"            "Make sure skycalc_cli is installed and working.\n"            "Try running:\n"            "    skycalc_cli --help"        ) from e    logger.info("Saved %s", output_file)    return output_file            def main():    """    Command-line entry point.    """    compute_sky()    if __name__ == "__main__":    main()